import { useState } from 'react';
import { useBreakpoint } from '@/hooks/useBreakpoint';

export function CodeReviewLayout({ tree, diff, comments }: { tree: React.ReactNode; diff: React.ReactNode; comments: React.ReactNode }) {
  const bp = useBreakpoint();
  const [tab, setTab] = useState<'tree' | 'diff' | 'comments'>('diff');

  if (bp === 'wide') {
    return (
      <div className="grid h-dvh grid-cols-[240px_1fr_300px] divide-x">
        <aside>{tree}</aside>
        <main>{diff}</main>
        <aside>{comments}</aside>
      </div>
    );
  }

  if (bp === 'desktop' || bp === 'tablet') {
    return (
      <div className="grid h-dvh grid-cols-[220px_1fr] divide-x">
        <aside>{tree}</aside>
        <main>{diff}</main>
      </div>
    );
  }

  // mobile
  return (
    <div className="flex flex-col h-dvh">
      <nav className="flex border-b" role="tablist">
        {(['tree', 'diff', 'comments'] as const).map((t) => (
          <button key={t} onClick={() => setTab(t)} role="tab" aria-selected={tab === t} className={`flex-1 min-h-11 ${tab === t ? 'border-b-2 border-blue-500' : ''}`}>{t}</button>
        ))}
      </nav>
      <main className="flex-1 overflow-y-auto">
        {tab === 'tree' && tree}
        {tab === 'diff' && diff}
        {tab === 'comments' && comments}
      </main>
    </div>
  );
}

// components/TruncatedCell.tsx
import { useRef, useState, useEffect } from 'react';

export function TruncatedCell({ children }: { children: string }) {
  const ref = useRef<HTMLSpanElement>(null);
  const [truncated, setTruncated] = useState(false);
  const [show, setShow] = useState(false);

  useEffect(() => {
    if (ref.current) {
      setTruncated(ref.current.scrollWidth > ref.current.clientWidth);
    }
  }, [children]);

  return (
    <span
      ref={ref}
      onMouseEnter={() => truncated && setShow(true)}
      onMouseLeave={() => setShow(false)}
      onFocus={() => truncated && setShow(true)}
      onBlur={() => setShow(false)}
      tabIndex={truncated ? 0 : -1}
      aria-label={truncated ? children : undefined}
      className="block truncate relative"
    >
      {children}
      {show && (
        <span role="tooltip" className="absolute left-0 top-full z-30 mt-1 max-w-xs rounded bg-neutral-900 text-white px-2 py-1 text-xs whitespace-normal shadow-lg">{children}</span>
      )}
    </span>
  );
}

