// components/CookieBanner.tsx
import { useState, useEffect } from 'react';

export function CookieBanner() {
  const [accepted, setAccepted] = useState(false);

  useEffect(() => {
    setAccepted(localStorage.getItem('cookies') === 'accepted');
  }, []);

  if (accepted) return null;

  const handle = (choice: 'accepted' | 'rejected') => {
    localStorage.setItem('cookies', choice);
    setAccepted(true);
  };

  return (
    <div
      role="dialog"
      aria-label="Cookie consent"
      className="fixed inset-x-0 bottom-0 z-40 bg-neutral-900 text-white p-4"
      style={{
        paddingBottom: 'max(1rem, env(safe-area-inset-bottom))',
        paddingLeft: 'max(1rem, env(safe-area-inset-left))',
        paddingRight: 'max(1rem, env(safe-area-inset-right))',
      }}
    >
      <p className="text-sm mb-3">We use cookies to improve your experience.</p>
      <div className="flex gap-2">
        <button onClick={() => handle('rejected')} className="flex-1 min-h-11 px-3 rounded border border-white">Reject</button>
        <button onClick={() => handle('accepted')} className="flex-1 min-h-11 px-3 rounded bg-white text-black">Accept</button>
      </div>
    </div>
  );
}

