import { useEffect, useState } from 'react';
import { useMediaQuery } from '@/hooks/useMediaQuery';

export function ShortcutsModal({ shortcuts }: { shortcuts: { keys: string; label: string }[] }) {
  const [open, setOpen] = useState(false);
  const hasKeyboard = useMediaQuery('(any-pointer: fine)', false);

  useEffect(() => {
    if (!hasKeyboard) return;
    const onKey = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && (e.key === '?' || e.key === '/')) {
        e.preventDefault();
        setOpen((o) => !o);
      }
      if (e.key === 'Escape') setOpen(false);
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [hasKeyboard]);

  if (!open) return null;
  return (
    <div role="dialog" aria-modal="true" className="fixed inset-0 z-50 flex items-center justify-center bg-black/50" onClick={() => setOpen(false)}>
      <div className="bg-white rounded-lg p-6 max-w-md" onClick={(e) => e.stopPropagation()}>
        <h2 className="text-lg font-semibold mb-4">Keyboard Shortcuts</h2>
        <ul className="space-y-2">
          {shortcuts.map((s, i) => (
            <li key={i} className="flex justify-between">
              <span>{s.label}</span>
              <kbd className="font-mono text-sm bg-neutral-100 px-2 py-0.5 rounded">{s.keys}</kbd>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

