import { useState } from 'react';

export function EditableRow({ data, onSave }: { data: { name: string; email: string }; onSave: (d: typeof data) => void }) {
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(data);

  if (editing) {
    return (
      <tr className="bg-blue-50">
        <td className="p-2"><input value={draft.name} onChange={(e) => setDraft({ ...draft, name: e.target.value })} className="w-full min-h-9 px-2 border rounded" /></td>
        <td className="p-2"><input value={draft.email} onChange={(e) => setDraft({ ...draft, email: e.target.value })} className="w-full min-h-9 px-2 border rounded" /></td>
        <td className="p-2 flex gap-1">
          <button onClick={() => { onSave(draft); setEditing(false); }} className="min-h-9 px-3 rounded bg-blue-500 text-white text-sm">Save</button>
          <button onClick={() => { setDraft(data); setEditing(false); }} className="min-h-9 px-3 rounded border text-sm">Cancel</button>
        </td>
