    </tr>
  );
}

// components/Waveform.tsx
import { useRef, useEffect } from 'react';
import { useElementSize } from '@/hooks/useElementSize';

export function Waveform({ data, progress }: { data: number[]; progress: number }) {
  const [ref, { width, height }] = useElementSize<HTMLDivElement>();
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || width === 0) return;
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext('2d')!;
    const barCount = Math.floor(width / 4);
    const step = data.length / barCount;

    for (let i = 0; i < barCount; i++) {
      const value = data[Math.floor(i * step)] || 0;
      const barHeight = value * height;
      const x = i * 4;
      ctx.fillStyle = (x / width) < progress ? '#3b82f6' : '#d4d4d8';
      ctx.fillRect(x, (height - barHeight) / 2, 2, barHeight);
    }
  }, [width, height, data, progress]);

  return (
    <div ref={ref} className="relative h-12 w-full">
      <canvas ref={canvasRef} />
    </div>
  );
}

